        const shift = data.zone_shift?.[zid] || data.zone_shift?.[parseInt(zid, 10)];
        if (!shift) return;
        const rot = data.zone_rot?.[zid] ?? data.zone_rot?.[parseInt(zid, 10)] ?? 0;
        const center = data.zone_center?.[zid] || data.zone_center?.[parseInt(zid, 10)] || [0,0];
